using System;

class Program
{
    static void Main()
    {
        // for dongusu
        Console.WriteLine("1'den 5'e kadar:");
        for (int i = 1; i <= 5; i++)
        {
            Console.WriteLine("Sayi: " + i);
        }

        // while dongusu
        Console.WriteLine("\nGeri sayim:");
        int counter = 5;
        while (counter > 0)
        {
            Console.WriteLine(counter);
            counter--;
        }

        // foreach dongusu
        Console.WriteLine("\nMeyveler:");
        string[] fruits = { "Elma", "Armut", "Muz", "Karpuz" };
        foreach (string fruit in fruits)
        {
            Console.WriteLine("- " + fruit);
        }

        // do-while dongusu
        Console.WriteLine("\nDo-while ornegi:");
        int n = 0;
        do
        {
            Console.WriteLine("n = " + n);
            n++;
        } while (n < 3);
    }
}
